table.ejecuta:
if ('barcode_cheque' != '') {
	$dir = str_replace('//', '/', $_SESSION['dirXML'].'../files/cheques/');
	$dir = realpath($dir).'/';
	$img = "barcode_front";
	$img = str_replace('data:image/jpeg;base64,', '', $img);
	$img = str_replace(' ', '+', $img);
	$file = str_replace(['=', '^'],'','barcode_cheque'.'_front.jpg');
	file_put_contents($dir.$file, base64_decode($img));

	$img = "barcode_back";
	$img = str_replace('data:image/jpeg;base64,', '', $img);
	$img = str_replace(' ', '+', $img);
	$file = str_replace(['=', '^'],'','barcode_cheque'.'_back.jpg');

	file_put_contents($dir.$file, base64_decode($img));
}
